var doc = Rhino.RhinoDoc.ActiveDoc;
var breps = new List<Rhino.Geometry.Brep>();
var pickedIds = new List<Guid>();
foreach (var obj in doc.Objects.GetSelectedObjects(false, false))
{
    if (obj.Geometry is Rhino.Geometry.Brep b) { breps.Add(b); pickedIds.Add(obj.Id); }
}
if (breps.Count < 2) return new { ok = false, error = $"need at least 2 selected breps; got {breps.Count}" };
var tol = doc.ModelAbsoluteTolerance;
var result = Rhino.Geometry.Brep.CreateBooleanUnion(breps, tol);
if (result == null || result.Length == 0) return new { ok = false, error = "boolean union returned no breps" };
foreach (var id in pickedIds) doc.Objects.Delete(id, true);
var newIds = new List<string>();
foreach (var brep in result) newIds.Add(doc.Objects.AddBrep(brep).ToString());
doc.Views.Redraw();
return new { ok = true, inputs = pickedIds.Count, outputs = newIds.Count, ids = newIds };
